import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { Star } from '@mui/icons-material';
import response from './response.json';

interface FeaturedDish {
  name: string;
  price: number;
  rating: number;
  reviews: number;
}

interface WidgetData {
  featuredDishes: FeaturedDish[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const featuredDishes = data.featuredDishes.slice(0, 3); // Ensure only 3 items are displayed

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
          Featured Dishes
        </Typography>
        <Stack spacing={2}>
          {featuredDishes.map((dish, index) => (
            <Box key={index}>
              <Typography variant="body1" fontWeight={500} sx={{ color: '#37474F' }}>
                {dish.name}
              </Typography>
              <Stack direction="row" alignItems="center" spacing={1}>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#FF5722' }}>
                  ${dish.price.toFixed(2)}
                </Typography>
                <Stack direction="row" alignItems="center" spacing={0.5}>
                  <Star sx={{ color: '#FFC107', fontSize: 16 }} />
                  <Typography variant="body2" sx={{ color: '#757575' }}>
                    {dish.rating} ({dish.reviews} reviews)
                  </Typography>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
